import{_ as e,o as t,c as i,aw as a}from"./chunks/framework.Dq2onT5h.js";const s=JSON.parse('{"title":"EVM Mainnet Checklist","description":"Checklist and guide for launching an EVM mainnet using ev-node and ev-reth.","frontmatter":{"description":"Checklist and guide for launching an EVM mainnet using ev-node and ev-reth.","head":[["meta",{"name":"og:title","content":"EVM Mainnet Checklist | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/deploy/mainnet.md","filePath":"guides/deploy/mainnet.md","lastUpdated":1771853702000}');const n=e({name:"guides/deploy/mainnet.md"},[["render",function(e,s,n,o,l,r){return t(),i("div",null,[...s[0]||(s[0]=[a('<h1 id="evm-mainnet-checklist" tabindex="-1">EVM Mainnet Checklist <a class="header-anchor" href="#evm-mainnet-checklist" aria-label="Permalink to &quot;EVM Mainnet Checklist&quot;">​</a></h1><p>This guide covers launching a mainnet using <strong>ev-reth</strong> and <strong>ev-node</strong>.</p><h2 id="ev-node" tabindex="-1">Ev-node <a class="header-anchor" href="#ev-node" aria-label="Permalink to &quot;Ev-node&quot;">​</a></h2><p>Ev-node is the sequencer that creates blocks, propagates them to other peers, and submits them to the DA layer.</p><h3 id="chain-id" tabindex="-1">Chain ID <a class="header-anchor" href="#chain-id" aria-label="Permalink to &quot;Chain ID&quot;">​</a></h3><ul><li>Pick a unique EVM chain ID for your network</li><li>Verify it does not collide with existing chains at <a href="https://chainlist.org" target="_blank" rel="noreferrer">chainlist.org</a></li></ul><h3 id="block-time" tabindex="-1">Block Time <a class="header-anchor" href="#block-time" aria-label="Permalink to &quot;Block Time&quot;">​</a></h3><ul><li>Pick a block time for your chain</li><li><strong>Optional:</strong> Decide if you would like lazy blocks</li></ul><h3 id="data-availability-da" tabindex="-1">Data Availability (DA) <a class="header-anchor" href="#data-availability-da" aria-label="Permalink to &quot;Data Availability (DA)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Configuration</th><th>Description</th></tr></thead><tbody><tr><td>Header Namespace</td><td>Required. Namespace for block headers.</td></tr><tr><td>Data Namespace</td><td>Required. Namespace for block data. Two namespaces are recommended, but one can be used.</td></tr><tr><td>Forced Inclusion Namespace</td><td>Optional. For censorship resistance.</td></tr><tr><td>DA Block Time</td><td>Used for syncing with the DA layer. Set this to the block time of the underlying DA chain.</td></tr></tbody></table><h4 id="batching-strategy" tabindex="-1">Batching Strategy <a class="header-anchor" href="#batching-strategy" aria-label="Permalink to &quot;Batching Strategy&quot;">​</a></h4><p>Blob submission to the DA layer is controlled by the batching strategy, not the DA block time. Choose a strategy based on your latency vs. cost trade-off:</p><table tabindex="0"><thead><tr><th>Strategy</th><th>Behavior</th></tr></thead><tbody><tr><td><code>immediate</code></td><td>Submits as soon as any items are available. Lowest latency, highest cost.</td></tr><tr><td><code>size</code></td><td>Waits until the batch reaches a size threshold (fraction of max blob size).</td></tr><tr><td><code>time</code></td><td>Waits for a time interval (<code>batch_max_delay</code>) before submitting. Default strategy.</td></tr><tr><td><code>adaptive</code></td><td>Submits when either the size threshold or the max delay is reached, whichever comes first.</td></tr></tbody></table><p>Related configuration flags:</p><ul><li><code>da.batching_strategy</code> -- Strategy name (default: <code>time</code>)</li><li><code>da.batch_size_threshold</code> -- Fraction of max blob size before submitting, 0.0-1.0 (default: 0.8). Applies to <code>size</code> and <code>adaptive</code>.</li><li><code>da.batch_max_delay</code> -- Maximum wait time before submitting regardless of size (default: DA block time). Applies to <code>time</code> and <code>adaptive</code>.</li><li><code>da.batch_min_items</code> -- Minimum items to accumulate before considering submission (default: 1).</li></ul><h4 id="da-account-funding" tabindex="-1">DA Account Funding <a class="header-anchor" href="#da-account-funding" aria-label="Permalink to &quot;DA Account Funding&quot;">​</a></h4><p>The DA account needs tokens to submit blobs to the DA layer. If the account runs dry, blob submission stops and your chain halts.</p><ul><li>Fund the DA account with sufficient tokens before launch</li><li>Set up balance monitoring with alerts at a threshold that gives you enough runway to top up (e.g. alert when balance drops below 48 hours of estimated submission costs)</li><li>Establish a process for topping up the DA account</li></ul><h3 id="sequencer-key-management" tabindex="-1">Sequencer Key Management <a class="header-anchor" href="#sequencer-key-management" aria-label="Permalink to &quot;Sequencer Key Management&quot;">​</a></h3><p>The sequencer signing key is the most security-critical component of your chain. A compromised key allows an attacker to produce arbitrary blocks.</p><ul><li>Use an HSM or remote signer for the sequencer key in production -- do not store plaintext keys on disk</li><li>Restrict access to the sequencer machine to a minimal set of operators</li><li>Have a key rotation plan ready before launch</li></ul><h3 id="p2p" tabindex="-1">P2P <a class="header-anchor" href="#p2p" aria-label="Permalink to &quot;P2P&quot;">​</a></h3><ul><li>Configure p2p peers for a stable network</li><li>The sequencer should be connected to <strong>at least two full nodes you control</strong></li><li>Third-party full nodes should connect to your full nodes, <strong>not</strong> directly to the sequencer</li></ul><h3 id="network-security" tabindex="-1">Network Security <a class="header-anchor" href="#network-security" aria-label="Permalink to &quot;Network Security&quot;">​</a></h3><ul><li>Place the sequencer behind a firewall; only allow p2p connections from your own full nodes</li><li>Apply rate limiting on public RPC endpoints to prevent abuse</li><li>Consider DDoS mitigation (e.g. Cloudflare, HAProxy) in front of public-facing full nodes</li><li>Restrict SSH and management ports to a VPN or bastion host</li></ul><h3 id="metrics-and-monitoring" tabindex="-1">Metrics and Monitoring <a class="header-anchor" href="#metrics-and-monitoring" aria-label="Permalink to &quot;Metrics and Monitoring&quot;">​</a></h3><ul><li>Set up a metric gathering system (Prometheus + Grafana recommended)</li><li>ev-metrics was created to help with basic metrics and alerting</li></ul><p>Key metrics to monitor:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Why</th></tr></thead><tbody><tr><td>Block production rate</td><td>Detect if the sequencer has stalled</td></tr><tr><td>DA submission lag / failures</td><td>Catch blob submission issues before they become critical</td></tr><tr><td>Peer count</td><td>Ensure network connectivity is healthy</td></tr><tr><td>Mempool depth</td><td>Detect congestion or spam</td></tr><tr><td>Disk usage</td><td>Prevent nodes from running out of storage</td></tr><tr><td>Sequencer balance</td><td>Ensure the sequencer can pay for DA submissions</td></tr><tr><td>DA account balance</td><td>Chain halts if this runs dry</td></tr><tr><td>RPC latency / error rate</td><td>Catch degraded user experience</td></tr></tbody></table><h3 id="rpc" tabindex="-1">RPC <a class="header-anchor" href="#rpc" aria-label="Permalink to &quot;RPC&quot;">​</a></h3><ul><li>Use the full nodes connected to the sequencer for public/application RPCs</li><li><strong>Do not expose the sequencer directly</strong></li></ul><h2 id="ev-reth" tabindex="-1">Ev-reth <a class="header-anchor" href="#ev-reth" aria-label="Permalink to &quot;Ev-reth&quot;">​</a></h2><p>Ev-reth is the execution engine. It uses reth as a library to make custom configurations for the Evolve use case. Changes are documented in the readme.</p><h3 id="precompiles" tabindex="-1">Precompiles <a class="header-anchor" href="#precompiles" aria-label="Permalink to &quot;Precompiles&quot;">​</a></h3><p>Ev-reth comes with a set of optional precompiles:</p><table tabindex="0"><thead><tr><th>Precompile</th><th>Description</th></tr></thead><tbody><tr><td>Basefee Redirect</td><td>Redirects the basefee (burned under EIP-1559) to a specified address</td></tr><tr><td>Native Mint &amp; Burn</td><td>Allows minting and burning the native token. Can be used with a bridge like Hyperlane.</td></tr></tbody></table><h3 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h3><ul><li>Decide which precompiles are needed</li><li>Set admin accounts for precompiles / basefee redirect</li><li>Decide if a proxy contract is needed (provided proxy contract)</li><li>Decide on EIP-1559 configurations</li><li>Configure basefee</li><li>Optional: Feevault contract</li></ul><h3 id="backup-and-recovery" tabindex="-1">Backup and Recovery <a class="header-anchor" href="#backup-and-recovery" aria-label="Permalink to &quot;Backup and Recovery&quot;">​</a></h3><p>Establish a backup and recovery strategy before launch. See the <a href="./../evm/reth-backup">Reth State Backup</a> guide for detailed instructions.</p><ul><li>Take periodic state snapshots (frequency depends on your RTO requirements)</li><li>Test the recovery procedure on a staging environment before mainnet launch</li><li>Keep at least one full node with archival state as a fallback</li><li>Document the recovery runbook so any operator can execute it</li></ul><h3 id="upgrade-strategy" tabindex="-1">Upgrade Strategy <a class="header-anchor" href="#upgrade-strategy" aria-label="Permalink to &quot;Upgrade Strategy&quot;">​</a></h3><p>Plan how you will ship new versions of ev-node and ev-reth to mainnet.</p><ul><li><strong>Rolling restart order:</strong> Upgrade full nodes first, then the sequencer. This ensures full nodes can handle the new version before the sequencer starts producing blocks with it.</li><li><strong>Hard fork coordination:</strong> If a release includes consensus-breaking changes, coordinate an activation height with all node operators in advance.</li><li><strong>Rollback plan:</strong> Know how to revert to the previous binary and state if an upgrade causes issues. Test this on a staging network.</li><li><strong>Communication:</strong> Establish a channel (Telegram, Discord, etc.) to notify node operators of upcoming upgrades and activation heights.</li></ul><h2 id="chain-startup-flow" tabindex="-1">Chain Startup Flow <a class="header-anchor" href="#chain-startup-flow" aria-label="Permalink to &quot;Chain Startup Flow&quot;">​</a></h2><h3 id="genesis" tabindex="-1">Genesis <a class="header-anchor" href="#genesis" aria-label="Permalink to &quot;Genesis&quot;">​</a></h3><p>Configuring the genesis is the first step to starting the chain.</p><p>If using the proxy admin contract alongside both native mint/burn and basefee redirect, set the admin of those to the proxy contract. This allows the chain to modify the admin to a multisig later.</p><h4 id="genesis-token-distribution" tabindex="-1">Genesis Token Distribution <a class="header-anchor" href="#genesis-token-distribution" aria-label="Permalink to &quot;Genesis Token Distribution&quot;">​</a></h4><p>Define the initial token supply and allocation before generating the genesis file.</p><ul><li>Decide the total initial supply and how it is split (team, treasury, partners, bridge reserves, etc.)</li><li>Configure genesis balances in the <code>alloc</code> section of the genesis file</li><li>Ensure the sequencer EOA has enough balance to submit transactions</li><li>If using a bridge (e.g. Hyperlane), reserve sufficient supply for the bridge contract</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>All flows below assume usage of the proxy admin contract.</p></div><h3 id="flow-1-full-setup" tabindex="-1">Flow 1: Full Setup <a class="header-anchor" href="#flow-1-full-setup" aria-label="Permalink to &quot;Flow 1: Full Setup&quot;">​</a></h3><p><strong>Basefee redirect + feevault + native mint/burn + bridge (Hyperlane)</strong></p><h4 id="genesis-setup" tabindex="-1">Genesis Setup <a class="header-anchor" href="#genesis-setup" aria-label="Permalink to &quot;Genesis Setup&quot;">​</a></h4><p>Embed the proxy contract with an EOA address as admin. The EOA must have at least one token to submit transactions. The proxy contract will have a predictable address, which is added to the <code>EvolveConfig</code> in the Chain Config as admin for feevault and native mint/burn.</p><p><strong>Steps:</strong></p><ol><li>Pick an EOA as admin of the proxy contract</li><li>Set EOA and create alloc of proxy contract for the genesis file</li><li>Set the admin proxy contract as admin in Evolve config:</li></ol><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;evolve&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;baseFeeSink&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;EOA_to_receive_funds&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;baseFeeRedirectActivationHeight&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mintAdmin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;EOA_admin/proxyContract&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mintPrecompileActivationHeight&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;contractSizeLimit&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">131072</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;contractSizeLimitActivationHeight&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ol start="4"><li>Pick a max contract size (24kb default, 128kb is a safe upgrade)</li><li>Pick EIP-1559 config:</li></ol><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;baseFeeMaxChangeDenominator&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;baseFeeElasticityMultiplier&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;initialBaseFeePerGas&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000000000</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h4 id="post-genesis" tabindex="-1">Post Genesis <a class="header-anchor" href="#post-genesis" aria-label="Permalink to &quot;Post Genesis&quot;">​</a></h4><ul><li>Deploy Hyperlane native mint contract (if using Hyperlane)</li><li>Provide funds to partner wallets deploying on your chain</li><li>Connect full nodes via reth p2p on top of the Evolve system (consult reth documentation for key discovery and connection)</li></ul><h3 id="flow-2-minimal-setup" tabindex="-1">Flow 2: Minimal Setup <a class="header-anchor" href="#flow-2-minimal-setup" aria-label="Permalink to &quot;Flow 2: Minimal Setup&quot;">​</a></h3><p><strong>Basefee redirect only, with an EOA receiving all funds.</strong></p><h4 id="genesis-setup-1" tabindex="-1">Genesis Setup <a class="header-anchor" href="#genesis-setup-1" aria-label="Permalink to &quot;Genesis Setup&quot;">​</a></h4><ol><li>Set EOA address as the sink in the Evolve config</li><li>Pick a max contract size (24kb default, 128kb is a safe upgrade)</li><li>Pick EIP-1559 config:</li></ol><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;baseFeeMaxChangeDenominator&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;baseFeeElasticityMultiplier&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;initialBaseFeePerGas&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000000000</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h4 id="post-genesis-1" tabindex="-1">Post Genesis <a class="header-anchor" href="#post-genesis-1" aria-label="Permalink to &quot;Post Genesis&quot;">​</a></h4><ul><li>Provide funds to partner wallets deploying on your chain</li><li>Connect full nodes via reth p2p on top of the Evolve system (consult reth documentation for key discovery and connection)</li></ul>',70)])])}]]);export{s as __pageData,n as default};
